B.a8l=new A.n(B.h,["Hello! I am your AI Roadside Mechanic. Tell me what's wrong with your vehicle, and I will help you diagnose the issue, provide safety tips, and guide you to find the right help.","\u0928\u092e\u0938\u094d\u0915\u093e\u0930! \u092e\u0948\u0902 \u0906\u092a\u0915\u093e \u090f\u0906\u0908 \u0930\u094b\u0921\u0938\u093e\u0907\u0921 \u092e\u0948\u0915\u0947\u0928\u093f\u0915 \u0939\u0942\u0901\u0964 \u092e\u0941\u091d\u0947 \u092c\u0924\u093e\u090f\u0902 \u0915\u093f \u0906\u092a\u0915\u0947 \u0935\u093e\u0939\u0928 \u092e\u0947\u0902 \u0915\u094d\u092f\u093e \u0916\u0930\u093e\u092c\u0940 \u0939\u0948, \u0914\u0930 \u092e\u0948\u0902 \u0906\u092a\u0915\u094b \u0938\u092e\u0938\u094d\u092f\u093e \u0915\u093e \u0928\u093f\u0926\u093e\u0928 \u0915\u0930\u0928\u0947, \u0938\u0941\u0930\u0915\u094d\u0937\u093e \u0938\u0941\u091d\u093e\u0935 \u092a\u094d\u0930\u0926\u093e\u0928 \u0915\u0930\u0928\u0947 \u0914\u0930 \u0938\u0939\u0940 \u092e\u0926\u0926 \u0916\u094b\u091c\u0928\u0947 \u092e\u0947\u0902 \u092e\u093e\u0930\u094d\u0917\u0926\u0930\u094d\u0936\u0928 \u0915\u0930\u0942\u0901\u0917\u093e\u0964","\u0c28\u0c2e\u0c38\u0c4d\u0c15\u0c3e\u0c30\u0c02! \u0c28\u0c47\u0c28\u0c41 \u0c2e\u0c40 AI \u0c30\u0c4b\u0c21\u0c4d\u200c\u0c38\u0c48\u0c21\u0c4d \u0c2e\u0c46\u0c15\u0c3e\u0c28\u0c3f\u0c15\u0c4d. \u0c2e\u0c40 \u0c35\u0c3e\u0c39\u0c28\u0c3e\u0c28\u0c3f\u0c15\u0c3f \u0c0f\u0c2e\u0c48\u0c02\u0c26\u0c4b \u0c28\u0c3e\u0c15\u0c41 \u0c1a\u0c46\u0c2a\u0c4d\u0c2a\u0c02\u0c21\u0c3f, \u0c28\u0c47\u0c28\u0c41 \u0c38\u0c2e\u0c38\u0c4d\u0c2f\u0c28\u0c41 \u0c17\u0c41\u0c30\u0c4d\u0c24\u0c3f\u0c02\u0c1a\u0c21\u0c02\u0c32\u0c4b, \u0c2d\u0c26\u0c4d\u0c30\u0c24\u0c3e \u0c1a\u0c3f\u0c1f\u0c4d\u0c15\u0c3e\u0c32\u0c28\u0c41 \u0c05\u0c02\u0c26\u0c3f\u0c02\u0c1a\u0c21\u0c02\u0c32\u0c4b \u0c2e\u0c30\u0c3f\u0c2f\u0c41 \u0c38\u0c30\u0c48\u0c28 \u0c38\u0c39\u0c3e\u0c2f\u0c3e\u0c28\u0c4d\u0c28\u0c3f \u0c15\u0c28\u0c41\u0c17\u0c4a\u0c28\u0c21\u0c02\u0c32\u0c4b \u0c2e\u0c40\u0c15\u0c41 \u0c38\u0c39\u0c3e\u0c2f\u0c02 \u0c1a\u0c47\u0c38\u0c4d\u0c24\u0c3e\u0c28\u0c41.","\u0bb5\u0ba3\u0b95\u0bcd\u0b95\u0bae\u0bcd! \u0ba8\u0bbe\u0ba9\u0bcd \u0b89\u0b99\u0bcd\u0b95\u0bb3\u0bcd AI \u0b9a\u0bbe\u0bb2\u0bc8\u0baf\u0bcb\u0bb0 \u0bae\u0bc6\u0b95\u0bcd\u0b95\u0bbe\u0ba9\u0bbf\u0b95\u0bcd. \u0b89\u0b99\u0bcd\u0b95\u0bb3\u0bcd \u0bb5\u0bbe\u0b95\u0ba9\u0ba4\u0bcd\u0ba4\u0bbf\u0bb2\u0bcd \u0b8e\u0ba9\u0bcd\u0ba9 \u0ba4\u0bb5\u0bb1\u0bc1 \u0b8e\u0ba9\u0bcd\u0bb1\u0bc1 \u0b9a\u0bca\u0bb2\u0bcd\u0bb2\u0bc1\u0b99\u0bcd\u0b95\u0bb3\u0bcd, \u0b9a\u0bbf\u0b95\u0bcd\u0b95\u0bb2\u0bc8\u0b95\u0bcd \u0b95\u0ba3\u0bcd\u0b9f\u0bb1\u0bbf\u0baf\u0bb5\u0bc1\u0bae\u0bcd, \u0baa\u0bbe\u0ba4\u0bc1\u0b95\u0bbe\u0baa\u0bcd\u0baa\u0bc1 \u0b89\u0ba4\u0bb5\u0bbf\u0b95\u0bcd\u0b95\u0bc1\u0bb1\u0bbf\u0baa\u0bcd\u0baa\u0bc1\u0b95\u0bb3\u0bc8 \u0bb5\u0bb4\u0b99\u0bcd\u0b95\u0bb5\u0bc1\u0bae\u0bcd, \u0b9a\u0bb0\u0bbf\u0baf\u0bbe\u0ba9 \u0b89\u0ba4\u0bb5\u0bbf\u0baf\u0bc8\u0b95\u0bcd \u0b95\u0ba3\u0bcd\u0b9f\u0bb1\u0bbf\u0baf\u0bb5\u0bc1\u0bae\u0bcd \u0ba8\u0bbe\u0ba9\u0bcd \u0b89\u0b99\u0bcd\u0b95\u0bb3\u0bc1\u0b95\u0bcd\u0b95\u0bc1 \u0b89\u0ba4\u0bb5\u0bc1\u0bb5\u0bc7\u0ba9\u0bcd."],t.w)
